export const EXAMPLES_HTML = `
<div class="question-card"><div class="question-header"><span class="q-number">Q 1</span></div><div class="question-body"><div class="question-text"><p>Convert 40° 20′ into radian measure.</p></div></div><div class="answer-section"><div class="solution-block"><div class="label">Solution</div><div><p>We know that 180° = <math xmlns="http://www.w3.org/1998/Math/MathML"><mi>π</mi></math> radians<br/> Hence, 40° 20′ = <math xmlns="http://www.w3.org/1998/Math/MathML"><mn>40</mn><mfrac><mn>1</mn><mn>3</mn></mfrac><mtext> degree </mtext><mo>=</mo><mfrac><mi>π</mi><mn>180</mn></mfrac><mo>×</mo><mfrac><mn>121</mn><mn>3</mn></mfrac><mtext> radian </mtext><mo>=</mo><mfrac><mrow><mn>121</mn><mi>π</mi></mrow><mn>540</mn></mfrac><mtext> radian </mtext></math><br/> Therefore, we have<br/> 40° 20′ = <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mrow><mn>121</mn><mi>π</mi></mrow><mn>540</mn></mfrac></math> radian</p></div></div></div><div class="question-actions"></div></div>
<div class="question-card"><div class="question-header"><span class="q-number">Q 2</span></div><div class="question-body"><div class="question-text"><p>Convert 6 radians into degree measure.</p></div></div><div class="answer-section"><div class="solution-block"><div class="label">Solution</div><div><p>We know, degree measure = <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mn>180</mn><mi>π</mi></mfrac></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>×</mo></math> radian measure<br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>∴</mo></math> Required degree measure<br/> = <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mn>180</mn><mfrac><mn>22</mn><mn>7</mn></mfrac></mfrac><mo>×</mo><mn>6</mn></math> [<math xmlns="http://www.w3.org/1998/Math/MathML"><mo>∵</mo><mi>π</mi><mo>=</mo><mfrac><mn>22</mn><mn>7</mn></mfrac></math>]<br/> = <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mrow><mn>1080</mn><mo>×</mo><mn>7</mn></mrow><mn>22</mn></mfrac></math> degree<br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>=</mo><mn>343</mn></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mn>7</mn><mn>11</mn></mfrac></math>degree<br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>=</mo><msup><mn>343</mn><mi>o</mi></msup><mo>+</mo></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mn>7</mn><mn>11</mn></mfrac></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>×</mo></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mn>60</mn><mtext></mtext><mi>m</mi><mi>i</mi><mi>n</mi></math> [<math xmlns="http://www.w3.org/1998/Math/MathML"><mo>∵</mo></math> 1<sup>o</sup> = 60']<br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>=</mo><msup><mn>343</mn><mi>o</mi></msup><mo>+</mo><mn>38</mn></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mn>2</mn><mn>11</mn></mfrac></math> min<br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>=</mo><msup><mn>343</mn><mi>o</mi></msup><mo>+</mo><msup><mn>38</mn><mo>′</mo></msup><mo>+</mo></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mn>2</mn><mn>11</mn></mfrac></math> min<br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>=</mo><msup><mn>343</mn><mi>o</mi></msup><mo>+</mo><msup><mn>38</mn><mo>′</mo></msup><mo>+</mo></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mn>2</mn><mn>11</mn></mfrac></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>×</mo></math> 60" <br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>=</mo><msup><mn>343</mn><mi>o</mi></msup><mo>+</mo><msup><mn>38</mn><mo>′</mo></msup><mo>+</mo><mn>10.9</mn><mo>"</mo></math><br/> = 343<sup>o</sup> 38' 11" (approx)<br/> Hence, 6 rad = 343<sup>o</sup> 38' 11" (approx)</p></div></div></div><div class="question-actions"></div></div>
<div class="question-card"><div class="question-header"><span class="q-number">Q 3</span></div><div class="question-body"><div class="question-text"><p>Find the radius of the circle in which a central angle of 60° intercepts an arc of length 37.4 cm (use <math xmlns="http://www.w3.org/1998/Math/MathML"><mi>π</mi><mo>=</mo><mfrac><mn>22</mn><mn>7</mn></mfrac></math>).</p></div></div><div class="answer-section"><div class="solution-block"><div class="label">Solution</div><div><p>Here length, <math xmlns="http://www.w3.org/1998/Math/MathML"><mi>l</mi></math> = 37.4 cm and <math xmlns="http://www.w3.org/1998/Math/MathML"><mi>θ</mi><mo>=</mo><msup><mn>60</mn><mrow class="MJX-TeXAtom-ORD"><mo>∘</mo></mrow></msup><mo>=</mo><mfrac><mrow><mn>60</mn><mi>π</mi></mrow><mn>180</mn></mfrac><mtext></mtext><mrow class="MJX-TeXAtom-ORD"><mi mathvariant="normal">r</mi><mi mathvariant="normal">a</mi><mi mathvariant="normal">d</mi><mi mathvariant="normal">i</mi><mi mathvariant="normal">a</mi><mi mathvariant="normal">n</mi></mrow><mo>=</mo><mfrac><mi>π</mi><mn>3</mn></mfrac></math><br/> Hence, by <math xmlns="http://www.w3.org/1998/Math/MathML"><mi>r</mi><mo>=</mo><mfrac><mi>l</mi><mi>θ</mi></mfrac></math>, we have<br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mi>r</mi><mo>=</mo><mfrac><mrow><mn>37.4</mn><mo>×</mo><mn>3</mn></mrow><mi>π</mi></mfrac><mo>=</mo><mfrac><mrow><mn>37.4</mn><mo>×</mo><mn>3</mn><mo>×</mo><mn>7</mn></mrow><mn>22</mn></mfrac></math> = 35.7 cm</p></div></div></div><div class="question-actions"></div></div>
<div class="question-card"><div class="question-header"><span class="q-number">Q 4</span></div><div class="question-body"><div class="question-text"><p>The minute hand of a watch is 1.5 cm long. How far does its tip move in 40 minutes? (Use <math xmlns="http://www.w3.org/1998/Math/MathML"><mi>π</mi></math> = 3.14).</p></div></div><div class="answer-section"><div class="solution-block"><div class="label">Solution</div><div><p>In 60 minutes, the minute hand of a watch completes one revolution.<br/> Therefore, in 40 minutes, the minute hand turns through <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mn>2</mn><mn>3</mn></mfrac></math> of a revolution.<br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>∴</mo></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mi>θ</mi><mo>=</mo><mfrac><mn>2</mn><mn>3</mn></mfrac><mo>×</mo><msup><mn>360</mn><mrow class="MJX-TeXAtom-ORD"><mo>∘</mo></mrow></msup></math> or <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mrow><mn>4</mn><mi>π</mi></mrow><mn>3</mn></mfrac></math> radian<br/> Hence, the required distance traveled is given by:<br/> x <math xmlns="http://www.w3.org/1998/Math/MathML"><mo>=</mo><mi>r</mi><mtext></mtext><mi>θ</mi><mo>=</mo><mn>1.5</mn><mo>×</mo><mfrac><mrow><mn>4</mn><mi>π</mi></mrow><mn>3</mn></mfrac><mrow class="MJX-TeXAtom-ORD"><mi mathvariant="normal">c</mi><mi mathvariant="normal">m</mi></mrow><mo>=</mo><mn>2</mn><mi>π</mi><mrow class="MJX-TeXAtom-ORD"><mi mathvariant="normal">c</mi><mi mathvariant="normal">m</mi></mrow><mo>=</mo><mn>2</mn><mo>×</mo><mn>3.14</mn><mrow class="MJX-TeXAtom-ORD"><mi mathvariant="normal">c</mi><mi mathvariant="normal">m</mi></mrow></math> = 6.28 cm</p></div></div></div><div class="question-actions"></div></div>
<div class="question-card"><div class="question-header"><span class="q-number">Q 5</span></div><div class="question-body"><div class="question-text"><p>If the arcs of the same lengths in two circles subtend angles 65<sup>o</sup> and 110<sup>o</sup> at the centre, find the ratio of their radii.</p></div></div><div class="answer-section"><div class="solution-block"><div class="label">Solution</div><div><p>Suppose <math xmlns="http://www.w3.org/1998/Math/MathML"><msub><mi>r</mi><mn>1</mn></msub></math> and <math xmlns="http://www.w3.org/1998/Math/MathML"><msub><mi>r</mi><mn>2</mn></msub></math> be the radii of two circles.<br/> Given, <math xmlns="http://www.w3.org/1998/Math/MathML"><mi>θ</mi></math><sub>1 </sub><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>=</mo><msup><mn>65</mn><mi>o</mi></msup></math><br/> = <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mi>π</mi><mn>180</mn></mfrac><mo>×</mo><mn>65</mn><mo>=</mo><mfrac><mrow><mn>13</mn><mi>π</mi></mrow><mn>36</mn></mfrac></math> rad<br/> [<math xmlns="http://www.w3.org/1998/Math/MathML"><mo>∵</mo></math> radian measure = <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mi>π</mi><mn>180</mn></mfrac><mo>×</mo></math> degree measure]<br/> and <math xmlns="http://www.w3.org/1998/Math/MathML"><mi>θ</mi></math><sub>2 </sub><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>=</mo><msup><mn>110</mn><mi>o</mi></msup></math><br/> = <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mi>π</mi><mn>180</mn></mfrac><mo>×</mo><mn>110</mn><mo>=</mo><mfrac><mrow><mn>22</mn><mi>π</mi></mrow><mn>36</mn></mfrac></math> rad<br/> Let <math xmlns="http://www.w3.org/1998/Math/MathML"><mi>l</mi></math> be the length of each of the arc. Then, <math xmlns="http://www.w3.org/1998/Math/MathML"><mi>l</mi><mo>=</mo><msub><mi>r</mi><mrow class="MJX-TeXAtom-ORD"><mn>1</mn></mrow></msub><msub><mi>θ</mi><mrow class="MJX-TeXAtom-ORD"><mn>1</mn></mrow></msub><mo>=</mo><msub><mi>r</mi><mrow class="MJX-TeXAtom-ORD"><mn>2</mn></mrow></msub><msub><mi>θ</mi><mrow class="MJX-TeXAtom-ORD"><mn>2</mn></mrow></msub></math><br/> i.e., <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><msub><mi>r</mi><mrow class="MJX-TeXAtom-ORD"><mn>1</mn></mrow></msub><msub><mi>r</mi><mrow class="MJX-TeXAtom-ORD"><mn>2</mn></mrow></msub></mfrac><mo>=</mo><mfrac><mn>22</mn><mn>13</mn></mfrac></math><br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>∴</mo></math><math xmlns="http://www.w3.org/1998/Math/MathML"><msub><mi>r</mi><mn>1</mn></msub><mo>:</mo><msub><mi>r</mi><mn>2</mn></msub><mo>=</mo><mn>22</mn><mo>:</mo><mn>13</mn></math></p></div></div></div><div class="question-actions"></div></div>
<div class="question-card"><div class="question-header"><span class="q-number">Q 6</span></div><div class="question-body"><div class="question-text"><p>If cos x = <math xmlns="http://www.w3.org/1998/Math/MathML"><mo>−</mo><mfrac><mn>3</mn><mn>5</mn></mfrac></math>, x lies in the third quadrant, find the values of other five trigonometric functions.</p></div></div><div class="answer-section"><div class="solution-block"><div class="label">Solution</div><div><p>Given: cos x = <math xmlns="http://www.w3.org/1998/Math/MathML"><mo>−</mo><mfrac><mn>3</mn><mn>5</mn></mfrac></math>, x lies in the third quadrant,<br/> Since cos x = <math xmlns="http://www.w3.org/1998/Math/MathML"><mo>−</mo><mfrac><mn>3</mn><mn>5</mn></mfrac></math>, we have sec x = <math xmlns="http://www.w3.org/1998/Math/MathML"><mo>−</mo><mfrac><mn>5</mn><mn>3</mn></mfrac></math><br/> Now sin<sup>2</sup> x + cos<sup>2</sup> x = 1, i.e., sin<sup>2</sup> x = 1 – cos<sup>2</sup> x<br/> or sin<sup>2</sup> x = <math xmlns="http://www.w3.org/1998/Math/MathML"><mn>1</mn><mo>−</mo><mfrac><mn>9</mn><mn>25</mn></mfrac><mo>=</mo><mfrac><mn>16</mn><mn>25</mn></mfrac></math><br/> Hence sin x = <math xmlns="http://www.w3.org/1998/Math/MathML"><mo>±</mo><mfrac><mn>4</mn><mn>5</mn></mfrac></math><br/> Since x lies in third quadrant, sin x is negative. Therefore<br/> sin x = <math xmlns="http://www.w3.org/1998/Math/MathML"><mo>−</mo><mfrac><mn>4</mn><mn>5</mn></mfrac></math><br/> which also gives<br/> cosec x = <math xmlns="http://www.w3.org/1998/Math/MathML"><mo>−</mo><mfrac><mn>5</mn><mn>4</mn></mfrac></math><br/> Further, we have<br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mi>tan</mi><mo>⁡</mo><mi>x</mi><mo>=</mo><mfrac><mrow><mi>sin</mi><mo>⁡</mo><mi>x</mi></mrow><mrow><mi>cos</mi><mo>⁡</mo><mi>x</mi></mrow></mfrac><mo>=</mo><mfrac><mn>4</mn><mn>3</mn></mfrac><mtext> and </mtext><mi>cot</mi><mo>⁡</mo><mi>x</mi><mo>=</mo><mfrac><mrow><mi>cos</mi><mo>⁡</mo><mi>x</mi></mrow><mrow><mi>sin</mi><mo>⁡</mo><mi>x</mi></mrow></mfrac><mo>=</mo><mfrac><mn>3</mn><mn>4</mn></mfrac></math></p></div></div></div><div class="question-actions"></div></div>
<div class="question-card"><div class="question-header"><span class="q-number">Q 7</span></div><div class="question-body"><div class="question-text"><p>If cot x <math xmlns="http://www.w3.org/1998/Math/MathML"><mo>=</mo><mo>−</mo><mfrac><mn>5</mn><mn>12</mn></mfrac></math>, x lies in second quadrant, find the values of other five trigonometric functions.<br/></p></div></div><div class="answer-section"><div class="solution-block"><div class="label">Solution</div><div><p>Given: cot x = <math xmlns="http://www.w3.org/1998/Math/MathML"><mo>=</mo><mo>−</mo><mfrac><mn>5</mn><mn>12</mn></mfrac></math>, x lies in second quadrant<br/> Since cot x = <math xmlns="http://www.w3.org/1998/Math/MathML"><mo>−</mo><mfrac><mn>5</mn><mn>12</mn></mfrac></math>, we have<br/> tan x = <math xmlns="http://www.w3.org/1998/Math/MathML"><mo>−</mo><mfrac><mn>12</mn><mn>5</mn></mfrac></math><br/> Now sec<sup>2</sup> x = 1 + tan<sup>2</sup> x = 1 + <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mn>144</mn><mn>25</mn></mfrac><mo>=</mo><mfrac><mn>169</mn><mn>25</mn></mfrac></math><br/> Hence sec x = <math xmlns="http://www.w3.org/1998/Math/MathML"><mo>=</mo><mo>±</mo><mfrac><mn>13</mn><mn>5</mn></mfrac></math><br/> Since x lies in second quadrant, sec x will be negative. Therefore<br/> sec x = <math xmlns="http://www.w3.org/1998/Math/MathML"><mo>−</mo><mfrac><mn>13</mn><mn>5</mn></mfrac></math>,<br/> Which also gives<br/> cos x = <math xmlns="http://www.w3.org/1998/Math/MathML"><mo>−</mo><mfrac><mn>5</mn><mn>13</mn></mfrac></math><br/> Further, we have<br/> sin x = tan x cos x = <math xmlns="http://www.w3.org/1998/Math/MathML"><mrow><mo>(</mo><mrow><mo>−</mo><mfrac><mn>12</mn><mn>5</mn></mfrac></mrow><mo>)</mo></mrow><mo>×</mo><mrow><mo>(</mo><mrow><mo>−</mo><mfrac><mn>5</mn><mn>13</mn></mfrac></mrow><mo>)</mo></mrow><mo>=</mo><mfrac><mn>12</mn><mn>13</mn></mfrac></math><br/> and cosec x = <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mn>1</mn><mrow><mi>sin</mi><mo>⁡</mo><mi>x</mi></mrow></mfrac><mo>=</mo><mfrac><mn>13</mn><mn>12</mn></mfrac></math></p></div></div></div><div class="question-actions"></div></div>
<div class="question-card"><div class="question-header"><span class="q-number">Q 8</span></div><div class="question-body"><div class="question-text"><p>Find the value of sin <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mrow><mn>31</mn><mi>π</mi></mrow><mn>3</mn></mfrac></math></p></div></div><div class="answer-section"><div class="solution-block"><div class="label">Solution</div><div><p>Let y = sin <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mrow><mn>31</mn><mi>π</mi></mrow><mn>3</mn></mfrac></math><br/> We know that values of sin x repeat after an interval of 2<math xmlns="http://www.w3.org/1998/Math/MathML"><mi>π</mi></math>. Therefore<br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mi>sin</mi><mo>⁡</mo><mfrac><mrow><mn>31</mn><mi>π</mi></mrow><mn>3</mn></mfrac><mo>=</mo><mi>sin</mi><mo>⁡</mo><mrow><mo>(</mo><mrow><mn>10</mn><mi>π</mi><mo>+</mo><mfrac><mi>π</mi><mn>3</mn></mfrac></mrow><mo>)</mo></mrow><mo>=</mo><mi>sin</mi><mo>⁡</mo><mfrac><mi>π</mi><mn>3</mn></mfrac><mo>=</mo><mfrac><msqrt><mn>3</mn></msqrt><mn>2</mn></mfrac></math></p></div></div></div><div class="question-actions"></div></div>
<div class="question-card"><div class="question-header"><span class="q-number">Q 9</span></div><div class="question-body"><div class="question-text"><p>Find the value of cos (–1710°).</p></div></div><div class="answer-section"><div class="solution-block"><div class="label">Solution</div><div><p>Let y = cos (–1710°)<br/> We know that values of cos x repeats after an interval of 2<math xmlns="http://www.w3.org/1998/Math/MathML"><mi>π</mi></math> or 360°.<br/> Therefore, we have<br/> y = cos (–1710°) = cos (–1710° + 5 <math xmlns="http://www.w3.org/1998/Math/MathML"><mo>×</mo></math> 360°) = cos (–1710° + 1800°) = cos 90° = 0</p></div></div></div><div class="question-actions"></div></div>
<div class="question-card"><div class="question-header"><span class="q-number">Q 10</span></div><div class="question-body"><div class="question-text"><p>Prove that: 3 sin <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mi>π</mi><mn>6</mn></mfrac></math> sec <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mi>π</mi><mn>3</mn></mfrac></math> -4 sin <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mrow><mn>5</mn><mi>π</mi></mrow><mn>6</mn></mfrac></math> cot <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mi>π</mi><mn>4</mn></mfrac></math> = 1.</p></div></div><div class="answer-section"><div class="solution-block"><div class="label">Solution</div><div><p><strong>LHS </strong><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>=</mo><mn>3</mn><mi>s</mi><mi>i</mi><mi>n</mi></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mi>π</mi><mn>6</mn></mfrac></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>×</mo></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mi>s</mi><mi>e</mi><mi>c</mi></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mi>π</mi><mn>3</mn></mfrac></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>−</mo><mn>4</mn><mi>s</mi><mi>i</mi><mi>n</mi></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mrow><mn>5</mn><mi>π</mi></mrow><mn>6</mn></mfrac></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>×</mo></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mi>c</mi><mi>o</mi><mi>t</mi></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mi>π</mi><mn>4</mn></mfrac></math><br/> = 3 <math xmlns="http://www.w3.org/1998/Math/MathML"><mo>×</mo></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mn>1</mn><mn>2</mn></mfrac></math> ​​​​​<math xmlns="http://www.w3.org/1998/Math/MathML"><mo>×</mo></math> 2 - 4 sin <math xmlns="http://www.w3.org/1998/Math/MathML"><mrow><mo>(</mo><mrow><mi>π</mi><mo>−</mo><mfrac><mi>π</mi><mn>6</mn></mfrac></mrow><mo>)</mo></mrow></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>×</mo></math> cot <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mi>π</mi><mn>4</mn></mfrac></math><br/> = 3 - 4 sin <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mi>π</mi><mn>6</mn></mfrac></math> ​<math xmlns="http://www.w3.org/1998/Math/MathML"><mo>×</mo></math> 1 [<math xmlns="http://www.w3.org/1998/Math/MathML"><mo>∵</mo></math> sin <math xmlns="http://www.w3.org/1998/Math/MathML"><mo stretchy="false">(</mo><mi>π</mi><mo>−</mo><mi>θ</mi><mo stretchy="false">)</mo></math> = sin <math xmlns="http://www.w3.org/1998/Math/MathML"><mi>θ</mi></math>]<br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>=</mo><mn>3</mn><mo>−</mo><mn>4</mn></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>×</mo></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mn>1</mn><mn>2</mn></mfrac></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>=</mo><mn>3</mn><mo>−</mo><mn>2</mn><mo>=</mo><mn>1</mn><mo>=</mo></math><strong>RHS</strong><br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>∴</mo></math><strong>LHS = RHS</strong><br/> Hence proved.​ </p></div></div></div><div class="question-actions"></div></div>
<div class="question-card"><div class="question-header"><span class="q-number">Q 11</span></div><div class="question-body"><div class="question-text"><p>Find the value of sin 15°</p></div></div><div class="answer-section"><div class="solution-block"><div class="label">Solution</div><div><p>Here we have,<br/> sin 15° = sin (45° – 30°)<br/> = sin 45° cos 30° – cos 45° sin 30°<br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>=</mo><mfrac><mn>1</mn><msqrt><mn>2</mn></msqrt></mfrac><mo>×</mo><mfrac><msqrt><mn>3</mn></msqrt><mn>2</mn></mfrac><mo>−</mo><mfrac><mn>1</mn><msqrt><mn>2</mn></msqrt></mfrac><mo>×</mo><mfrac><mn>1</mn><mn>2</mn></mfrac><mo>=</mo><mfrac><mrow><msqrt><mn>3</mn></msqrt><mo>−</mo><mn>1</mn></mrow><mrow><mn>2</mn><msqrt><mn>2</mn></msqrt></mrow></mfrac></math></p></div></div></div><div class="question-actions"></div></div>
<div class="question-card"><div class="question-header"><span class="q-number">Q 12</span></div><div class="question-body"><div class="question-text"><p>Find the value of tan <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mrow><mn>13</mn><mi>π</mi></mrow><mn>12</mn></mfrac></math></p></div></div><div class="answer-section"><div class="solution-block"><div class="label">Solution</div><div><p>Here we have,<br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mi>tan</mi><mo>⁡</mo><mfrac><mrow><mn>13</mn><mi>π</mi></mrow><mn>12</mn></mfrac><mo>=</mo><mi>tan</mi><mo>⁡</mo><mrow><mo>(</mo><mrow><mi>π</mi><mo>+</mo><mfrac><mi>π</mi><mn>12</mn></mfrac></mrow><mo>)</mo></mrow><mo>=</mo><mi>tan</mi><mo>⁡</mo><mfrac><mi>π</mi><mn>12</mn></mfrac><mo>=</mo><mi>tan</mi><mo>⁡</mo><mrow><mo>(</mo><mrow><mfrac><mi>π</mi><mn>4</mn></mfrac><mo>−</mo><mfrac><mi>π</mi><mn>6</mn></mfrac></mrow><mo>)</mo></mrow></math><br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>=</mo><mfrac><mrow><mi>tan</mi><mo>⁡</mo><mfrac><mi>π</mi><mn>4</mn></mfrac><mo>−</mo><mi>tan</mi><mo>⁡</mo><mfrac><mi>π</mi><mn>6</mn></mfrac></mrow><mrow><mn>1</mn><mo>+</mo><mi>tan</mi><mo>⁡</mo><mfrac><mi>π</mi><mn>4</mn></mfrac><mi>tan</mi><mo>⁡</mo><mfrac><mi>π</mi><mn>6</mn></mfrac></mrow></mfrac><mo>=</mo><mfrac><mrow><mn>1</mn><mo>−</mo><mfrac><mn>1</mn><msqrt><mn>3</mn></msqrt></mfrac></mrow><mrow><mn>1</mn><mo>+</mo><mfrac><mn>1</mn><msqrt><mn>3</mn></msqrt></mfrac></mrow></mfrac><mo>=</mo><mfrac><mrow><msqrt><mn>3</mn></msqrt><mo>−</mo><mn>1</mn></mrow><mrow><msqrt><mn>3</mn></msqrt><mo>+</mo><mn>1</mn></mrow></mfrac><mo>=</mo><mn>2</mn><mo>−</mo><msqrt><mn>3</mn></msqrt></math></p></div></div></div><div class="question-actions"></div></div>
<div class="question-card"><div class="question-header"><span class="q-number">Q 13</span></div><div class="question-body"><div class="question-text"><p>Prove that: <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mrow><mi>sin</mi><mo>⁡</mo><mo stretchy="false">(</mo><mi>x</mi><mo>+</mo><mi>y</mi><mo stretchy="false">)</mo></mrow><mrow><mi>sin</mi><mo>⁡</mo><mo stretchy="false">(</mo><mi>x</mi><mo>−</mo><mi>y</mi><mo stretchy="false">)</mo></mrow></mfrac><mo>=</mo><mfrac><mrow><mi>tan</mi><mo>⁡</mo><mi>x</mi><mo>+</mo><mi>tan</mi><mo>⁡</mo><mi>y</mi></mrow><mrow><mi>tan</mi><mo>⁡</mo><mi>x</mi><mo>−</mo><mi>tan</mi><mo>⁡</mo><mi>y</mi></mrow></mfrac></math></p></div></div><div class="answer-section"><div class="solution-block"><div class="label">Solution</div><div><p>Here we have, L.H.S. = <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mrow><mi>sin</mi><mo>⁡</mo><mo stretchy="false">(</mo><mi>x</mi><mo>+</mo><mi>y</mi><mo stretchy="false">)</mo></mrow><mrow><mi>sin</mi><mo>⁡</mo><mo stretchy="false">(</mo><mi>x</mi><mo>−</mo><mi>y</mi><mo stretchy="false">)</mo></mrow></mfrac><mo>=</mo><mfrac><mrow><mi>sin</mi><mo>⁡</mo><mi>x</mi><mi>cos</mi><mo>⁡</mo><mi>y</mi><mo>+</mo><mi>cos</mi><mo>⁡</mo><mi>x</mi><mi>sin</mi><mo>⁡</mo><mi>y</mi></mrow><mrow><mi>sin</mi><mo>⁡</mo><mi>x</mi><mi>cos</mi><mo>⁡</mo><mi>y</mi><mo>−</mo><mi>cos</mi><mo>⁡</mo><mi>x</mi><mi>sin</mi><mo>⁡</mo><mi>y</mi></mrow></mfrac></math><br/> Dividing the numerator and denominator by cos x cos y, we get<br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mrow><mi>sin</mi><mo>⁡</mo><mo stretchy="false">(</mo><mi>x</mi><mo>+</mo><mi>y</mi><mo stretchy="false">)</mo></mrow><mrow><mi>sin</mi><mo>⁡</mo><mo stretchy="false">(</mo><mi>x</mi><mo>−</mo><mi>y</mi><mo stretchy="false">)</mo></mrow></mfrac><mo>=</mo><mfrac><mrow><mi>tan</mi><mo>⁡</mo><mi>x</mi><mo>+</mo><mi>tan</mi><mo>⁡</mo><mi>y</mi></mrow><mrow><mi>tan</mi><mo>⁡</mo><mi>x</mi><mo>−</mo><mi>tan</mi><mo>⁡</mo><mi>y</mi></mrow></mfrac></math><br/> Hence proved.</p></div></div></div><div class="question-actions"></div></div>
<div class="question-card"><div class="question-header"><span class="q-number">Q 14</span></div><div class="question-body"><div class="question-text"><p>Show that tan 3 x tan 2 x tan x = tan 3x – tan 2 x – tan x</p></div></div><div class="answer-section"><div class="solution-block"><div class="label">Solution</div><div><p>To prove: tan 3 x tan 2 x tan x = tan 3x – tan 2 x – tan x<br/> We know that 3x = 2x + x<br/> Therefore, tan 3x = tan (2x + x)<br/> or <math xmlns="http://www.w3.org/1998/Math/MathML"><mi>tan</mi><mo>⁡</mo><mn>3</mn><mi>x</mi><mo>=</mo><mfrac><mrow><mi>tan</mi><mo>⁡</mo><mn>2</mn><mi>x</mi><mo>+</mo><mi>tan</mi><mo>⁡</mo><mi>x</mi></mrow><mrow><mn>1</mn><mo>−</mo><mi>tan</mi><mo>⁡</mo><mn>2</mn><mi>x</mi><mi>tan</mi><mo>⁡</mo><mi>x</mi></mrow></mfrac></math><br/> or tan 3x – tan 3x tan 2x tan x = tan 2x + tan x<br/> or tan 3x – tan 2x – tan x = tan 3x tan 2x tan x<br/> or tan 3x tan 2x tan x = tan 3x – tan 2x – tan x<br/> Hence proved.</p></div></div></div><div class="question-actions"></div></div>
<div class="question-card"><div class="question-header"><span class="q-number">Q 15</span></div><div class="question-body"><div class="question-text"><p>Prove that: <math xmlns="http://www.w3.org/1998/Math/MathML"><mi>cos</mi><mo>⁡</mo><mrow><mo>(</mo><mrow><mfrac><mi>π</mi><mn>4</mn></mfrac><mo>+</mo><mi>x</mi></mrow><mo>)</mo></mrow><mo>+</mo><mi>cos</mi><mo>⁡</mo><mrow><mo>(</mo><mrow><mfrac><mi>π</mi><mn>4</mn></mfrac><mo>−</mo><mi>x</mi></mrow><mo>)</mo></mrow><mo>=</mo><msqrt><mn>2</mn></msqrt><mi>cos</mi><mo>⁡</mo><mi>x</mi></math></p></div></div><div class="answer-section"><div class="solution-block"><div class="label">Solution</div><div><p>Take L.H.S. we have <br/> LHS = <math xmlns="http://www.w3.org/1998/Math/MathML"><mi>cos</mi><mo>⁡</mo><mrow><mo>(</mo><mrow><mfrac><mi>π</mi><mn>4</mn></mfrac><mo>+</mo><mi>x</mi></mrow><mo>)</mo></mrow><mo>+</mo><mi>cos</mi><mo>⁡</mo><mrow><mo>(</mo><mrow><mfrac><mi>π</mi><mn>4</mn></mfrac><mo>−</mo><mi>x</mi></mrow><mo>)</mo></mrow></math><br/> Using the cos x + cos y = <math xmlns="http://www.w3.org/1998/Math/MathML"><mn>2</mn><mtext></mtext><mi>cos</mi><mo>⁡</mo><mo stretchy="false">(</mo><mfrac><mrow><mi>x</mi><mo>+</mo><mi>y</mi></mrow><mn>2</mn></mfrac><mo stretchy="false">)</mo><mi>cos</mi><mo>⁡</mo><mo stretchy="false">(</mo><mfrac><mrow><mi>x</mi><mo>−</mo><mi>y</mi></mrow><mn>2</mn></mfrac><mo stretchy="false">)</mo></math>, we have<br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mi>L</mi><mo>.</mo><mi>H</mi><mo>.</mo><mi>S</mi><mo>=</mo><mn>2</mn><mi>cos</mi><mo>⁡</mo><mrow><mo>(</mo><mfrac><mrow><mfrac><mi>π</mi><mn>4</mn></mfrac><mo>+</mo><mi>x</mi><mo>+</mo><mfrac><mi>π</mi><mn>4</mn></mfrac><mo>−</mo><mi>x</mi></mrow><mn>2</mn></mfrac><mo>)</mo></mrow><mi>cos</mi><mo>⁡</mo><mrow><mo>(</mo><mfrac><mrow><mfrac><mi>π</mi><mn>4</mn></mfrac><mo>+</mo><mi>x</mi><mo>−</mo><mrow><mo>(</mo><mrow><mfrac><mi>π</mi><mn>4</mn></mfrac><mo>−</mo><mi>x</mi></mrow><mo>)</mo></mrow></mrow><mn>2</mn></mfrac><mo>)</mo></mrow></math><br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>=</mo><mn>2</mn><mi>cos</mi><mo>⁡</mo><mfrac><mi>π</mi><mn>4</mn></mfrac><mi>cos</mi><mo>⁡</mo><mi>x</mi><mo>=</mo><mn>2</mn><mo>×</mo><mfrac><mn>1</mn><msqrt><mn>2</mn></msqrt></mfrac><mi>cos</mi><mo>⁡</mo><mi>x</mi><mo>=</mo><msqrt><mn>2</mn></msqrt><mi>cos</mi><mo>⁡</mo><mi>x</mi></math> = R.H.S.<br/> Hence proved.</p></div></div></div><div class="question-actions"></div></div>
<div class="question-card"><div class="question-header"><span class="q-number">Q 16</span></div><div class="question-body"><div class="question-text"><p>Prove that <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mrow><mi>cos</mi><mo>⁡</mo><mn>7</mn><mi>x</mi><mo>+</mo><mi>cos</mi><mo>⁡</mo><mn>5</mn><mi>x</mi></mrow><mrow><mi>sin</mi><mo>⁡</mo><mn>7</mn><mi>x</mi><mo>−</mo><mi>sin</mi><mo>⁡</mo><mn>5</mn><mi>x</mi></mrow></mfrac><mo>=</mo><mi>cot</mi><mo>⁡</mo><mi>x</mi></math></p></div></div><div class="answer-section"><div class="solution-block"><div class="label">Solution</div><div><p>Taking L.H.S, we have<br/> LHS = <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mrow><mi>cos</mi><mo>⁡</mo><mn>7</mn><mi>x</mi><mo>+</mo><mi>cos</mi><mo>⁡</mo><mn>5</mn><mi>x</mi></mrow><mrow><mi>sin</mi><mo>⁡</mo><mn>7</mn><mi>x</mi><mo>−</mo><mi>sin</mi><mo>⁡</mo><mn>5</mn><mi>x</mi></mrow></mfrac></math><br/> Using the cos x + cos y = <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mrow><mi>x</mi><mo>+</mo><mi>y</mi></mrow><mn>2</mn></mfrac><mi>cos</mi><mo>⁡</mo><mfrac><mrow><mi>x</mi><mo>−</mo><mi>y</mi></mrow><mn>2</mn></mfrac></math> and sin x – sin y = <math xmlns="http://www.w3.org/1998/Math/MathML"><mn>2</mn><mi>cos</mi><mo>⁡</mo><mfrac><mrow><mi>x</mi><mo>+</mo><mi>y</mi></mrow><mn>2</mn></mfrac><mi>sin</mi><mo>⁡</mo><mfrac><mrow><mi>x</mi><mo>−</mo><mi>y</mi></mrow><mn>2</mn></mfrac></math>, we have<br/> L.H.S. = <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mrow><mn>2</mn><mi>cos</mi><mo>⁡</mo><mfrac><mrow><mn>7</mn><mi>x</mi><mo>+</mo><mn>5</mn><mi>x</mi></mrow><mn>2</mn></mfrac><mi>cos</mi><mo>⁡</mo><mfrac><mrow><mn>7</mn><mi>x</mi><mo>−</mo><mn>5</mn><mi>x</mi></mrow><mn>2</mn></mfrac></mrow><mrow><mn>2</mn><mi>cos</mi><mo>⁡</mo><mfrac><mrow><mn>7</mn><mi>x</mi><mo>+</mo><mn>5</mn><mi>x</mi></mrow><mn>2</mn></mfrac><mi>sin</mi><mo>⁡</mo><mfrac><mrow><mn>7</mn><mi>x</mi><mo>−</mo><mn>5</mn><mi>x</mi></mrow><mn>2</mn></mfrac></mrow></mfrac><mo>=</mo><mfrac><mrow><mi>cos</mi><mo>⁡</mo><mi>x</mi></mrow><mrow><mi>sin</mi><mo>⁡</mo><mi>x</mi></mrow></mfrac></math> = cot x = R.H.S. </p></div></div></div><div class="question-actions"></div></div>
<div class="question-card"><div class="question-header"><span class="q-number">Q 17</span></div><div class="question-body"><div class="question-text"><p>Prove that: <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mrow><mi>sin</mi><mo>⁡</mo><mn>5</mn><mi>x</mi><mo>−</mo><mn>2</mn><mi>sin</mi><mo>⁡</mo><mn>3</mn><mi>x</mi><mo>+</mo><mi>sin</mi><mo>⁡</mo><mi>x</mi></mrow><mrow><mi>cos</mi><mo>⁡</mo><mn>5</mn><mi>x</mi><mo>−</mo><mi>cos</mi><mo>⁡</mo><mi>x</mi></mrow></mfrac><mo>=</mo><mi>tan</mi><mo>⁡</mo><mi>x</mi></math></p></div></div><div class="answer-section"><div class="solution-block"><div class="label">Solution</div><div><p>Take L.H.S. we have,<br/> LHS = <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mrow><mi>sin</mi><mo>⁡</mo><mn>5</mn><mi>x</mi><mo>−</mo><mn>2</mn><mi>sin</mi><mo>⁡</mo><mn>3</mn><mi>x</mi><mo>+</mo><mi>sin</mi><mo>⁡</mo><mi>x</mi></mrow><mrow><mi>cos</mi><mo>⁡</mo><mn>5</mn><mi>x</mi><mo>−</mo><mi>cos</mi><mo>⁡</mo><mi>x</mi></mrow></mfrac><mo>=</mo><mfrac><mrow><mi>sin</mi><mo>⁡</mo><mn>5</mn><mi>x</mi><mo>+</mo><mi>sin</mi><mo>⁡</mo><mi>x</mi><mo>−</mo><mn>2</mn><mi>sin</mi><mo>⁡</mo><mn>3</mn><mi>x</mi></mrow><mrow><mi>cos</mi><mo>⁡</mo><mn>5</mn><mi>x</mi><mo>−</mo><mi>cos</mi><mo>⁡</mo><mi>x</mi></mrow></mfrac></math><br/> = <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mrow><mn>2</mn><mi>sin</mi><mo>⁡</mo><mn>3</mn><mi>x</mi><mi>cos</mi><mo>⁡</mo><mn>2</mn><mi>x</mi><mo>−</mo><mn>2</mn><mi>sin</mi><mo>⁡</mo><mn>3</mn><mi>x</mi></mrow><mrow><mo>−</mo><mn>2</mn><mi>sin</mi><mo>⁡</mo><mn>3</mn><mi>x</mi><mi>sin</mi><mo>⁡</mo><mn>2</mn><mi>x</mi></mrow></mfrac><mo>=</mo><mo>−</mo><mfrac><mrow><mi>sin</mi><mo>⁡</mo><mn>3</mn><mi>x</mi><mo stretchy="false">(</mo><mi>cos</mi><mo>⁡</mo><mn>2</mn><mi>x</mi><mo>−</mo><mn>1</mn><mo stretchy="false">)</mo></mrow><mrow><mi>sin</mi><mo>⁡</mo><mn>3</mn><mi>x</mi><mi>sin</mi><mo>⁡</mo><mn>2</mn><mi>x</mi></mrow></mfrac></math><br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>=</mo><mfrac><mrow><mn>1</mn><mo>−</mo><mi>cos</mi><mo>⁡</mo><mn>2</mn><mi>x</mi></mrow><mrow><mi>sin</mi><mo>⁡</mo><mn>2</mn><mi>x</mi></mrow></mfrac><mo>=</mo><mfrac><mrow><mn>2</mn><msup><mi>sin</mi><mrow class="MJX-TeXAtom-ORD"><mn>2</mn></mrow></msup><mo>⁡</mo><mi>x</mi></mrow><mrow><mn>2</mn><mi>sin</mi><mo>⁡</mo><mi>x</mi><mi>cos</mi><mo>⁡</mo><mi>x</mi></mrow></mfrac></math> = tan x = R.H.S.<br/> Hence proved.</p></div></div></div><div class="question-actions"></div></div>
<div class="question-card"><div class="question-header"><span class="q-number">Q 18</span></div><div class="question-body"><div class="question-text"><p>If sin x = <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mn>3</mn><mn>5</mn></mfrac></math>, cos y = - <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mn>12</mn><mn>13</mn></mfrac></math>, where x and y both lie in second quadrant, find the value of sin (x + y)</p></div></div><div class="answer-section"><div class="solution-block"><div class="label">Solution</div><div><p>Given: sin x = <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mn>3</mn><mn>5</mn></mfrac></math>, cos y = - <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mn>12</mn><mn>13</mn></mfrac></math><br/> We know that sin (x + y) = sin x cos y + cos x sin y ........ (i)<br/> Now cos<sup>2</sup> x = 1 – sin<sup>2</sup> x = 1 <math xmlns="http://www.w3.org/1998/Math/MathML"><mo>−</mo><mfrac><mn>9</mn><mn>25</mn></mfrac><mo>=</mo><mfrac><mn>16</mn><mn>25</mn></mfrac></math><br/> Therefore <math xmlns="http://www.w3.org/1998/Math/MathML"><mi>cos</mi><mo>⁡</mo><mi>x</mi><mo>=</mo><mo>±</mo><mfrac><mn>4</mn><mn>5</mn></mfrac></math><br/> Since x lies in second quadrant, cos x is negative.<br/> Hence cos x = <math xmlns="http://www.w3.org/1998/Math/MathML"><mo>−</mo><mfrac><mn>4</mn><mn>5</mn></mfrac></math><br/> Now sin<sup>2</sup>y = 1 - cos<sup>2</sup>y = <math xmlns="http://www.w3.org/1998/Math/MathML"><mn>1</mn><mo>−</mo><mfrac><mn>144</mn><mn>169</mn></mfrac><mo>=</mo><mfrac><mn>25</mn><mn>169</mn></mfrac></math><br/> i.e. <math xmlns="http://www.w3.org/1998/Math/MathML"><mi>sin</mi><mo>⁡</mo><mi>y</mi><mo>=</mo><mo>±</mo><mfrac><mn>5</mn><mn>13</mn></mfrac></math><br/> Since y lies in second quadrant, hence sin y is positive.<br/> Therefore, sin y = <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mn>5</mn><mn>13</mn></mfrac></math>Substituting the values of sin x, sin y, cos x and cos y in (i), we get<br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mi>sin</mi><mo>⁡</mo><mo stretchy="false">(</mo><mi>x</mi><mo>+</mo><mi>y</mi><mo stretchy="false">)</mo><mo>=</mo><mfrac><mn>3</mn><mn>5</mn></mfrac><mo>×</mo><mrow><mo>(</mo><mrow><mo>−</mo><mfrac><mn>12</mn><mn>13</mn></mfrac></mrow><mo>)</mo></mrow><mo>+</mo><mrow><mo>(</mo><mrow><mo>−</mo><mfrac><mn>4</mn><mn>5</mn></mfrac></mrow><mo>)</mo></mrow><mo>×</mo><mfrac><mn>5</mn><mn>13</mn></mfrac><mspace width="1em"></mspace><mo>=</mo><mo>−</mo><mfrac><mn>36</mn><mn>65</mn></mfrac><mo>−</mo><mfrac><mn>20</mn><mn>65</mn></mfrac><mo>=</mo><mo>−</mo><mfrac><mn>56</mn><mn>65</mn></mfrac></math></p></div></div></div><div class="question-actions"></div></div>
<div class="question-card"><div class="question-header"><span class="q-number">Q 19</span></div><div class="question-body"><div class="question-text"><p>Prove that: <math xmlns="http://www.w3.org/1998/Math/MathML"><mi>cos</mi><mo>⁡</mo><mn>2</mn><mi>x</mi><mi>cos</mi><mo>⁡</mo><mfrac><mi>x</mi><mn>2</mn></mfrac><mo>−</mo><mi>cos</mi><mo>⁡</mo><mn>3</mn><mi>x</mi><mi>cos</mi><mo>⁡</mo><mfrac><mrow><mn>9</mn><mi>x</mi></mrow><mn>2</mn></mfrac></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>=</mo><mi>sin</mi><mo>⁡</mo><mn>5</mn><mi>x</mi><mi>sin</mi><mo>⁡</mo><mfrac><mrow><mn>5</mn><mi>x</mi></mrow><mn>2</mn></mfrac></math></p></div></div><div class="answer-section"><div class="solution-block"><div class="label">Solution</div><div><p>LHS <math xmlns="http://www.w3.org/1998/Math/MathML"><mo>=</mo><mi>cos</mi><mo>⁡</mo><mn>2</mn><mi>x</mi><mi>cos</mi><mo>⁡</mo><mfrac><mi>x</mi><mn>2</mn></mfrac><mo>−</mo><mi>cos</mi><mo>⁡</mo><mn>3</mn><mi>x</mi><mi>cos</mi><mo>⁡</mo><mfrac><mrow><mn>9</mn><mi>x</mi></mrow><mn>2</mn></mfrac></math><br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mo stretchy="false">⇒</mo><mrow class="MJX-TeXAtom-ORD"><mi mathvariant="normal">L</mi><mi mathvariant="normal">H</mi><mi mathvariant="normal">S</mi></mrow><mo>=</mo><mfrac><mn>1</mn><mn>2</mn></mfrac><mrow><mo>{</mo><mrow><mn>2</mn><mi>cos</mi><mo>⁡</mo><mn>2</mn><mi>x</mi><mi>cos</mi><mo>⁡</mo><mfrac><mi>x</mi><mn>2</mn></mfrac><mo>−</mo><mn>2</mn><mi>cos</mi><mo>⁡</mo><mn>3</mn><mi>x</mi><mi>cos</mi><mo>⁡</mo><mfrac><mrow><mn>9</mn><mi>x</mi></mrow><mn>2</mn></mfrac></mrow><mo>}</mo></mrow></math><br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mo stretchy="false">⇒</mo><mrow class="MJX-TeXAtom-ORD"><mi mathvariant="normal">L</mi><mi mathvariant="normal">H</mi><mi mathvariant="normal">S</mi></mrow><mo>=</mo><mfrac><mn>1</mn><mn>2</mn></mfrac><mrow><mo>[</mo><mrow><mi>cos</mi><mo>⁡</mo><mrow><mo>{</mo><mrow><mrow><mo>(</mo><mrow><mn>2</mn><mi>x</mi><mo>+</mo><mfrac><mi>x</mi><mn>2</mn></mfrac></mrow><mo>)</mo></mrow><mo>+</mo><mi>cos</mi><mo>⁡</mo><mrow><mo>(</mo><mrow><mn>2</mn><mi>x</mi><mo>−</mo><mfrac><mi>x</mi><mn>2</mn></mfrac></mrow><mo>)</mo></mrow></mrow><mo>}</mo></mrow></mrow><mo fence="true" stretchy="true" symmetric="true"></mo></mrow></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>−</mo><mrow><mo>{</mo><mrow><mi>cos</mi><mo>⁡</mo><mrow><mo>(</mo><mrow><mn>3</mn><mi>x</mi><mo>+</mo><mfrac><mrow><mn>9</mn><mi>x</mi></mrow><mn>2</mn></mfrac></mrow><mo>)</mo></mrow><mo>+</mo><mi>cos</mi><mo>⁡</mo><mrow><mo>(</mo><mrow><mfrac><mrow><mn>9</mn><mi>x</mi></mrow><mn>2</mn></mfrac><mo>−</mo><mn>3</mn><mi>x</mi></mrow><mo>)</mo></mrow></mrow><mo>}</mo></mrow><mo stretchy="false">]</mo></math>[Using: 2 cos A cos B = cos (A + B) + cos (A - B)]<br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mo stretchy="false">⇒</mo><mrow class="MJX-TeXAtom-ORD"><mi mathvariant="normal">L</mi><mi mathvariant="normal">H</mi><mi mathvariant="normal">S</mi></mrow><mo>=</mo><mfrac><mn>1</mn><mn>2</mn></mfrac><mrow><mo>{</mo><mrow><mi>cos</mi><mo>⁡</mo><mfrac><mrow><mn>5</mn><mi>x</mi></mrow><mn>2</mn></mfrac><mo>+</mo><mi>cos</mi><mo>⁡</mo><mfrac><mrow><mn>3</mn><mi>x</mi></mrow><mn>2</mn></mfrac><mo>−</mo><mi>cos</mi><mo>⁡</mo><mfrac><mrow><mn>15</mn><mi>x</mi></mrow><mn>2</mn></mfrac><mo>−</mo><mi>cos</mi><mo>⁡</mo><mfrac><mrow><mn>3</mn><mi>x</mi></mrow><mn>2</mn></mfrac></mrow><mo>}</mo></mrow></math><br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mo stretchy="false">⇒</mo><mrow class="MJX-TeXAtom-ORD"><mi mathvariant="normal">L</mi><mi mathvariant="normal">H</mi><mi mathvariant="normal">S</mi></mrow><mo>=</mo><mfrac><mn>1</mn><mn>2</mn></mfrac><mrow><mo>{</mo><mrow><mi>cos</mi><mo>⁡</mo><mfrac><mrow><mn>5</mn><mi>x</mi></mrow><mn>2</mn></mfrac><mo>−</mo><mi>cos</mi><mo>⁡</mo><mfrac><mrow><mn>15</mn><mi>x</mi></mrow><mn>2</mn></mfrac></mrow><mo>}</mo></mrow></math><br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mrow><mo fence="true" stretchy="true" symmetric="true"></mo><mrow class="MJX-TeXAtom-ORD"><mo stretchy="false">⇒</mo><mspace width="1em"></mspace><mrow class="MJX-TeXAtom-ORD"><mtext>LHS</mtext></mrow><mo>=</mo><mfrac><mn>1</mn><mn>2</mn></mfrac><mrow><mo>{</mo><mrow class="MJX-TeXAtom-ORD"><mn>2</mn><mi>sin</mi><mo>⁡</mo><mrow><mo>(</mo><mrow class="MJX-TeXAtom-ORD"><mfrac><mrow class="MJX-TeXAtom-ORD"><mfrac><mrow class="MJX-TeXAtom-ORD"><mn>5</mn><mi>x</mi></mrow><mn>2</mn></mfrac><mo>+</mo><mfrac><mrow class="MJX-TeXAtom-ORD"><mn>15</mn><mi>x</mi></mrow><mn>2</mn></mfrac></mrow><mn>2</mn></mfrac></mrow><mo>)</mo></mrow><mi>sin</mi><mo>⁡</mo><mrow><mo>(</mo><mrow class="MJX-TeXAtom-ORD"><mfrac><mrow class="MJX-TeXAtom-ORD"><mfrac><mrow class="MJX-TeXAtom-ORD"><mn>15</mn><mi>x</mi></mrow><mn>2</mn></mfrac><mo>−</mo><mfrac><mrow class="MJX-TeXAtom-ORD"><mn>5</mn><mi>x</mi></mrow><mn>2</mn></mfrac></mrow><mn>2</mn></mfrac></mrow><mo>)</mo></mrow></mrow><mo fence="true" stretchy="true" symmetric="true"></mo></mrow></mrow><mo>}</mo></mrow></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mrow><mo>[</mo><mrow><mo>∵</mo><mi>cos</mi><mo>⁡</mo><mi>C</mi><mo>−</mo><mi>cos</mi><mo>⁡</mo><mi>D</mi><mo>=</mo><mn>2</mn><mi>sin</mi><mo>⁡</mo><mfrac><mrow><mi>C</mi><mo>+</mo><mi>D</mi></mrow><mn>2</mn></mfrac><mi>sin</mi><mo>⁡</mo><mfrac><mrow><mi>D</mi><mo>−</mo><mi>C</mi></mrow><mn>2</mn></mfrac></mrow><mo>]</mo></mrow></math><br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mo stretchy="false">⇒</mo></math> LHS = sin (5x) sin (<math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mrow><mn>5</mn><mi>x</mi></mrow><mn>2</mn></mfrac></math>) = RHS<br/> Hence proved.</p></div></div></div><div class="question-actions"></div></div>
<div class="question-card"><div class="question-header"><span class="q-number">Q 20</span></div><div class="question-body"><div class="question-text"><p>Find the value of tan <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mi>π</mi><mn>8</mn></mfrac></math>.</p></div></div><div class="answer-section"><div class="solution-block"><div class="label">Solution</div><div><p>Suppose, <math xmlns="http://www.w3.org/1998/Math/MathML"><mi>x</mi><mo>=</mo></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mi>π</mi><mn>8</mn></mfrac></math><br/> Then, <math xmlns="http://www.w3.org/1998/Math/MathML"><mn>2</mn><mi>x</mi><mo>=</mo></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mi>π</mi><mn>4</mn></mfrac></math><br/> Now, <math xmlns="http://www.w3.org/1998/Math/MathML"><mi>t</mi><mi>a</mi><mi>n</mi><mn>2</mn><mi>x</mi><mo>=</mo></math> tan <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mi>π</mi><mn>4</mn></mfrac></math><br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mo stretchy="false">⇒</mo><mspace width="1em"></mspace><mfrac><mrow><mn>2</mn><mi>tan</mi><mo>⁡</mo><mi>x</mi></mrow><mrow><mn>1</mn><mo>−</mo><msup><mi>tan</mi><mrow class="MJX-TeXAtom-ORD"><mn>2</mn></mrow></msup><mo>⁡</mo><mi>x</mi></mrow></mfrac><mo>=</mo><mi>tan</mi><mo>⁡</mo><mfrac><mi>π</mi><mn>4</mn></mfrac></math> [<math xmlns="http://www.w3.org/1998/Math/MathML"><mo>∵</mo></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mi>t</mi><mi>a</mi><mi>n</mi><mn>2</mn><mi>x</mi><mo>=</mo></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mrow><mn>2</mn><mi>tan</mi><mo>⁡</mo><mi>x</mi></mrow><mrow><mn>1</mn><mo>−</mo><msup><mi>tan</mi><mrow class="MJX-TeXAtom-ORD"><mn>2</mn></mrow></msup><mo>⁡</mo><mi>x</mi></mrow></mfrac></math>]<br/> Putting x = <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mi>π</mi><mn>8</mn></mfrac></math>, <br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mo stretchy="false">⇒</mo><mfrac><mrow><mn>2</mn><mi>tan</mi><mo>⁡</mo><mfrac><mi>π</mi><mn>8</mn></mfrac></mrow><mrow><mn>1</mn><mo>−</mo><msup><mi>tan</mi><mrow class="MJX-TeXAtom-ORD"><mn>2</mn></mrow></msup><mo>⁡</mo><mfrac><mi>π</mi><mn>8</mn></mfrac></mrow></mfrac></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>=</mo><mn>1</mn></math><br/> Let y = tan <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mi>π</mi><mn>8</mn></mfrac></math><br/> Then, <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mrow><mn>2</mn><mi>y</mi></mrow><mrow><mn>1</mn><mo>−</mo><msup><mi>y</mi><mrow class="MJX-TeXAtom-ORD"><mn>2</mn></mrow></msup></mrow></mfrac></math> = 1<br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mo stretchy="false">⇒</mo></math><math xmlns="http://www.w3.org/1998/Math/MathML"><mn>2</mn><mi>y</mi><mo>=</mo><mn>1</mn><mo>−</mo><msup><mi>y</mi><mn>2</mn></msup></math><br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mo stretchy="false">⇒</mo></math><math xmlns="http://www.w3.org/1998/Math/MathML"><msup><mi>y</mi><mn>2</mn></msup><mo>+</mo><mn>2</mn><mi>y</mi><mo>−</mo><mn>1</mn><mo>=</mo><mn>0</mn></math><br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mo>∴</mo></math> y = <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mrow><mo>−</mo><mn>2</mn><mo>±</mo><msqrt><mo stretchy="false">(</mo><mn>2</mn><msup><mo stretchy="false">)</mo><mrow class="MJX-TeXAtom-ORD"><mn>2</mn></mrow></msup><mo>+</mo><mn>4</mn></msqrt></mrow><mn>2</mn></mfrac><mo>=</mo><mfrac><mrow><mo>−</mo><mn>2</mn><mo>±</mo><msqrt><mn>8</mn></msqrt></mrow><mn>2</mn></mfrac><mo>=</mo><mfrac><mrow><mo>−</mo><mn>2</mn><mo>±</mo><mn>2</mn><msqrt><mn>2</mn></msqrt></mrow><mn>2</mn></mfrac></math><br/><math xmlns="http://www.w3.org/1998/Math/MathML"><mo stretchy="false">⇒</mo></math> y = - 1 <math xmlns="http://www.w3.org/1998/Math/MathML"><mo>±</mo><msqrt><mn>2</mn></msqrt></math><br/> But <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mi>π</mi><mn>8</mn></mfrac></math> lies in I quadrant, so y = tan <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mi>π</mi><mn>8</mn></mfrac></math> is positive.<br/> Hence, tan <math xmlns="http://www.w3.org/1998/Math/MathML"><mfrac><mi>π</mi><mn>8</mn></mfrac></math> = - 1 + <math xmlns="http://www.w3.org/1998/Math/MathML"><msqrt><mn>2</mn></msqrt></math></p></div></div></div><div class="question-actions"></div></div>
`;

